const score = $input.first().json.data.overallScore;
const color = score >= 80 ? '#36a64f' : score >= 60 ? '#ffa500' : '#ff0000';

return {
  channel: '#seo-audits',
  text: '🔍 SEO Audit Complete',
  attachments: [{
    color: color,
    title: $input.first().json.data.domain,
    fields: [
      { title: 'Score', value: `${score}/100`, short: true },
      { title: 'Critical Issues', value: String($input.first().json.data.criticalIssues), short: true },
      { title: 'High Issues', value: String($input.first().json.data.highIssues), short: true },
      { title: 'Total Findings', value: String($input.first().json.data.findingsCount), short: true }
    ],
    footer: 'SEO Audit Pro'
  }]
};
